import { Box, Container, Spacer, VStack ,Checkbox, Input } from "@chakra-ui/react"
import { useState } from "react"

export const IncompleteTodos = (props) => {
    const { incompleteTodos, onClickComplete, onClickDelete } = props;


    const [editing, setEditing] = useState();

    const onClickUpdate = () => {
      {editing ? (<input></input>) : (<input></input>)}
    }

    return (
    <div>
            <VStack>
            <Container maxW='xl' bg='blue.600' color='white'>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo, index) => (
          <li key={todo}>
            <Box display="flex" p={2}>
            <Checkbox onChange={() => onClickComplete(index)}></Checkbox>
            <p>{todo}</p>
            <Spacer />
            <Box px={2}>
            <button onClick={() => onClickUpdate(index)}>編集</button>
            </Box>
            <button onClick={() => onClickDelete(index)}>削除</button>

            </Box>
          </li>
            )
        )}
        </ul>
        </Container>
        </VStack>
    </div>
    )
}
